const d = $('On form submission').first().json;
const folderId = $('Create folder').first().json.id;

const now = new Date();
const studentId = 'CT' + now.getFullYear() + String(Math.floor(Math.random() * 9000) + 1000);

const fee = parseFloat(String(d.fee).replace(/[^0-9.]/g, ''));
const emiCount = parseInt(String(d.emiCount)) || 0;
const monthlyEMI = emiCount > 0 ? (fee / emiCount).toFixed(2) : 'N/A';
const durationMonths = parseInt(String(d.duration).replace(/[^0-9]/g, ''));

const startDate = new Date(d.startDate);
const endDate = new Date(startDate);
endDate.setMonth(endDate.getMonth() + durationMonths);

const formatDate = (dt) => dt.toLocaleDateString('en-IN', {
  day:'2-digit', month:'2-digit', year:'numeric'
});

const formattedStartDate = formatDate(startDate);
const formattedEndDate = formatDate(endDate);

const installments = emiCount > 0 ? (() => {
  let rows = '';
  for (let i = 0; i < emiCount; i++) {
    const emiDate = new Date(startDate);
    emiDate.setMonth(emiDate.getMonth() + i);
    rows += `
      <tr>
        <td>${i + 1}. ${formatDate(emiDate)}</td>
        <td>: ${monthlyEMI}</td>
      </tr>`;
  }
  return rows;
})() : '<tr><td colspan="2">No EMI — Full Payment</td></tr>';

